#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAXN 1000000
int main(){
    bool *isPrime = calloc(MAXN+1, sizeof(bool));
    for(int i=2;i<=MAXN;i++) isPrime[i]=true;
    for(int i=2;i*i<=MAXN;i++) if(isPrime[i]) for(int j=i*i;j<=MAXN;j+=i) isPrime[j]=false;
    int *primes = malloc((MAXN/10)*sizeof(int)); // enough space
    int pcnt=0;
    for(int i=2;i<=MAXN;i++) if(isPrime[i]) primes[pcnt++]=i;
    int n;
    while(scanf("%d", &n)==1 && n!=0){
        int ans1=0, ans2=0, ans3=0;
        for(int i=0;i<pcnt && (long long)primes[i]*primes[i]*primes[i]<=n-2;i++){
            int p3=primes[i];
            int rem1 = n - p3*p3*p3;
            for(int j=0;j<pcnt && (long long)primes[j]*primes[j]<=rem1-2;j++){
                int p2=primes[j];
                int rem2 = rem1 - p2*p2;
                if(rem2>=2 && isPrime[rem2]){
                    ans1=rem2; ans2=p2; ans3=p3; goto done;
                }
            }
        }
        done:
        printf("%d %d %d\n", ans1, ans2, ans3);
    }
    free(isPrime);
    free(primes);
    return 0;
}

