import java.io.*;
import java.util.*;
public class Main {
    static final int MAXN = 1_000_000;
    public static void main(String[] args) throws Exception {
        boolean[] isPrime = new boolean[MAXN+1];
        Arrays.fill(isPrime, true);
        isPrime[0]=isPrime[1]=false;
        for(int i=2;i*i<=MAXN;i++) if(isPrime[i]) for(int j=i*i;j<=MAXN;j+=i) isPrime[j]=false;
        List<Integer> primes = new ArrayList<>();
        for(int i=2;i<=MAXN;i++) if(isPrime[i]) primes.add(i);
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        StringBuilder sb = new StringBuilder();
        while((line=br.readLine())!=null){
            line=line.trim();
            if(line.isEmpty()) continue;
            int n = Integer.parseInt(line);
            if(n==0) break;
            int a=0,b=0,c=0;
            outer:
            for(int p3:primes){
                long cube = 1L*p3*p3*p3;
                if(cube > n-2) break;
                long rem1 = n - cube;
                for(int p2:primes){
                    long sq = 1L*p2*p2;
                    if(sq > rem1-2) break;
                    long rem2 = rem1 - sq;
                    if(rem2>=2 && rem2<=MAXN && isPrime[(int)rem2]){
                        a = (int)rem2; b = p2; c = p3;
                        break outer;
                    }
                }
            }
            sb.append(a).append(' ').append(b).append(' ').append(c).append('\n');
        }
        System.out.print(sb.toString());
    }
}

